-- 80 سؤال — الوحدة الأولى: الأعداد النسبية — ثاني متوسط
-- استورد هذا الملف من phpMyAdmin مرة واحدة فقط
SET NAMES utf8mb4;

DELETE FROM questions WHERE grade_key = 'second' AND unit_index = 0;

INSERT INTO questions
  (grade_key, unit_index, lesson_index, question_text, question_hash,
   option_a, option_b, option_c, option_d, correct_answer, explanation)
VALUES
  ('second', 0, 0, 'أيٌّ من الأعداد التالية لا يُعدُّ من الأعداد النسبية؟', SHA2('أيٌّ من الأعداد التالية لا يُعدُّ من الأعداد النسبية؟', 256),
   '3/4', '-7', '0.252525… (مكرَّر)', '√5', 4, 'العدد النسبي هو كل عدد يمكن كتابته على صورة أ/ب حيث ب ≠ 0. الكسر 3/4 نسبي، والعدد -7 يُكتب -7/1 فهو نسبي، والعدد العشري الدوري 0.2525… نسبي لأنه يمكن تحويله إلى كسر. أمّا √5 فهو عدد غير نسبي لأنه عدد عشري غير منتهٍ وغير دوري ولا يمكن كتابته على صورة كسر.'),
  ('second', 0, 0, 'ما صورة العدد 5/8 على هيئة عدد عشري؟', SHA2('ما صورة العدد 5/8 على هيئة عدد عشري؟', 256),
   '0.625', '0.58', '0.85', '1.6', 1, 'نقسم البسط على المقام: 5 ÷ 8. نضع علامة عشرية ونتابع: 50 ÷ 8 = 6 والباقي 2. ننزل صفراً: 20 ÷ 8 = 2 والباقي 4. ننزل صفراً: 40 ÷ 8 = 5 والباقي 0. الناتج 0.625، وهو عدد عشري منتهٍ.'),
  ('second', 0, 0, 'اكتب العدد العشري 0.36 على صورة كسر اعتيادي في أبسط صورة.', SHA2('اكتب العدد العشري 0.36 على صورة كسر اعتيادي في أبسط صورة.', 256),
   '9/25', '36/10', '18/100', '3/8', 1, 'نلاحظ أن 0.36 يحوي رقمين بعد الفاصلة، فنكتبه 36/100. ثم نُبسِّطه بقسمة البسط والمقام على 4 (وهو القاسم المشترك الأكبر): 36 ÷ 4 = 9، و100 ÷ 4 = 25. النتيجة 9/25.'),
  ('second', 0, 0, 'أيُّ الأعداد العشرية التالية يُعدُّ دورياً (مكرَّراً)؟', SHA2('أيُّ الأعداد العشرية التالية يُعدُّ دورياً (مكرَّراً)؟', 256),
   '0.5', '0.25', '0.6666…', '0.125', 3, 'العدد العشري الدوري هو الذي يحوي رقماً (أو مجموعة أرقام) تتكرّر بلا انتهاء. القيم 0.5 و0.25 و0.125 منتهية لأن قسمتها تقف عند باقٍ صفر. أمّا 0.6666… فالرقم 6 يتكرّر بلا توقف، ويُكتب اختصاراً 0.6 مع شرطة فوق الـ6.'),
  ('second', 0, 0, 'ما العدد العشري المكافئ للكسر 4/11؟', SHA2('ما العدد العشري المكافئ للكسر 4/11؟', 256),
   '0.36', '0.3636… (دوري)', '0.4', '0.44', 2, 'بقسمة 4 ÷ 11: نحصل على 0.3636… حيث يتكرّر النمط 36 بلا توقف. القاعدة: إذا كان مقام الكسر بعد التبسيط يحوي عاملاً غير 2 و5 (مثل 11)، فإن الكسر يُعطي عدداً عشرياً دورياً.'),
  ('second', 0, 0, 'حوِّل العدد الكسري 2 و3/5 إلى عدد عشري.', SHA2('حوِّل العدد الكسري 2 و3/5 إلى عدد عشري.', 256),
   '2.35', '2.6', '2.06', '2.3', 2, 'العدد الكسري 2 و3/5 = 2 + 3/5. نحوِّل الكسر: 3 ÷ 5 = 0.6. ثم نجمع: 2 + 0.6 = 2.6. خطأ شائع: الخلط بين 2 و3/5 وبين 2.35 (وهي 2 و35/100).'),
  ('second', 0, 0, 'اكتب العدد العشري الدوري 0.4444… على صورة كسر اعتيادي.', SHA2('اكتب العدد العشري الدوري 0.4444… على صورة كسر اعتيادي.', 256),
   '4/9', '4/10', '44/99', '1/4', 1, 'نضع س = 0.4444… ثم نضرب الطرفين في 10 لنحصل على 10س = 4.4444… بطرح المعادلتين: 10س - س = 4.4444… - 0.4444… أي 9س = 4، إذن س = 4/9. تذكَّر: عدد دوري برقم واحد متكرر = الرقم/9.'),
  ('second', 0, 0, 'أيُّ الأعداد التالية يكافئ -1.75؟', SHA2('أيُّ الأعداد التالية يكافئ -1.75؟', 256),
   '-1 و3/4', '-1 و1/4', '-7/4', '(أ) و(ج) معاً', 4, 'الجزء الكسري 0.75 = 75/100 = 3/4. إذن -1.75 = -1 و3/4. ولأنه عدد كسري سالب، فإنه يكافئ الكسر غير الفعلي -7/4 (لأن 1×4 + 3 = 7). كلا الصورتين صحيحة. درِّب نفسك على التنقل بين الصور الثلاث: عشري، كسري، كسر غير فعلي.'),
  ('second', 0, 0, 'إذا كان مقام كسر بعد تبسيطه ٢٥، فما طبيعة العدد العشري المكافئ له؟', SHA2('إذا كان مقام كسر بعد تبسيطه ٢٥، فما طبيعة العدد العشري المكافئ له؟', 256),
   'دوري دائماً', 'منتهٍ دائماً', 'غير نسبي', 'صحيح فقط', 2, 'قاعدة مهمّة: إذا كان مقام الكسر (في أبسط صورة) يحوي العوامل الأولية 2 و5 فقط، فإن الكسر يُعطي عدداً عشرياً منتهياً. وبما أن 25 = 5×5، فإن مقامه يتكوّن من العامل 5 فقط، ولذا فالعدد العشري الناتج منتهٍ. مثال: 7/25 = 0.28.'),
  ('second', 0, 0, 'اختر عدداً نسبياً يقع بين 1/3 و1/2.', SHA2('اختر عدداً نسبياً يقع بين 1/3 و1/2.', 256),
   '5/12', '1/4', '2/3', '5/6', 1, 'نوحّد المقامات بأخذ المضاعف المشترك الأصغر للعددين 3 و2 وهو 6: 1/3 = 2/6، و1/2 = 3/6. لا يوجد عدد بمقام 6 بينهما، فنوسِّع إلى مقام 12: 1/3 = 4/12، و1/2 = 6/12. الكسر 5/12 يقع بينهما. والقيم: 1/4 = 0.25 (أصغر من 1/3)، 2/3 ≈ 0.67، 5/6 ≈ 0.83 (أكبر من 1/2).'),
  ('second', 0, 1, 'أيُّ العلامات تجعل العبارة التالية صحيحة:  3/5 □ 0.7؟', SHA2('أيُّ العلامات تجعل العبارة التالية صحيحة:  3/5 □ 0.7؟', 256),
   '<', '>', '=', 'لا يمكن المقارنة', 1, 'نحوِّل 3/5 إلى عشري: 3 ÷ 5 = 0.6. والآن نقارن 0.6 بـ 0.7. الأكبر هو 0.7. إذن 3/5 < 0.7.'),
  ('second', 0, 1, 'أي الأعداد التالية أكبر؟', SHA2('أي الأعداد التالية أكبر؟', 256),
   '-2/3', '-3/4', '-5/6', '-1', 1, 'في الأعداد السالبة، كلما كانت القيمة المطلقة أصغر كان العدد أكبر (لأنه أقرب إلى الصفر). نوحّد: -2/3 = -8/12، -3/4 = -9/12، -5/6 = -10/12، -1 = -12/12. الأكبر هو -8/12 = -2/3.'),
  ('second', 0, 1, 'رتِّب الأعداد التالية تصاعدياً: 0.45،  1/2،  0.4،  3/8.', SHA2('رتِّب الأعداد التالية تصاعدياً: 0.45،  1/2،  0.4،  3/8.', 256),
   '0.4 < 3/8 < 0.45 < 1/2', '3/8 < 0.4 < 0.45 < 1/2', '1/2 < 0.45 < 0.4 < 3/8', '3/8 < 0.45 < 0.4 < 1/2', 2, 'نحوّل الجميع إلى أعداد عشرية: 1/2 = 0.5، 3/8 = 0.375. أصبح لدينا: 0.45، 0.5، 0.4، 0.375. ترتيبها تصاعدياً: 0.375 < 0.4 < 0.45 < 0.5، أي 3/8 < 0.4 < 0.45 < 1/2.'),
  ('second', 0, 1, 'أيُّ الكسور التالية أصغر من 5/8؟', SHA2('أيُّ الكسور التالية أصغر من 5/8؟', 256),
   '7/8', '3/4', '1/2', '11/16', 3, 'نوحّد المقامات بمقام مشترك 16: 5/8 = 10/16، 7/8 = 14/16، 3/4 = 12/16، 1/2 = 8/16، 11/16 = 11/16. الأصغر من 10/16 هو 8/16 فقط، أي 1/2.'),
  ('second', 0, 1, 'ما الكسر الذي يقع في الموقع المؤشَّر بالسهم على خط الأعداد إذا كان السهم في منتصف المسافة بين 1/4 و1/2 ؟', SHA2('ما الكسر الذي يقع في الموقع المؤشَّر بالسهم على خط الأعداد إذا كان السهم في منتصف المسافة بين 1/4 و1/2 ؟', 256),
   '3/8', '1/3', '5/16', '3/4', 1, 'نقطة المنتصف بين عددين = (مجموعهما) ÷ 2. (1/4 + 1/2) ÷ 2 = (1/4 + 2/4) ÷ 2 = (3/4) ÷ 2 = 3/8. ولذلك يكون الكسر المُؤشَّر إليه هو 3/8.'),
  ('second', 0, 1, 'أيُّ الأعداد التالية يقع بين -0.4 و-0.5؟', SHA2('أيُّ الأعداد التالية يقع بين -0.4 و-0.5؟', 256),
   '-7/15', '-3/5', '-1/3', '-0.6', 1, 'نحوّل الخيارات إلى أعداد عشرية تقريباً: -7/15 ≈ -0.4666، -3/5 = -0.6، -1/3 ≈ -0.333، -0.6 = -0.6. القيمة المطلوبة بين 0.4 و0.5 هي تلك التي تقع بين -0.4 و-0.5، وهي -0.4666 أي -7/15.'),
  ('second', 0, 1, 'في حصة الرياضة، حصل ثلاثة طلاب على الدرجات: أحمد 17/20، خالد 0.84، فيصل 4/5. مَن الأعلى درجة؟', SHA2('في حصة الرياضة، حصل ثلاثة طلاب على الدرجات: أحمد 17/20، خالد 0.84، فيصل 4/5. مَن الأعلى درجة؟', 256),
   'أحمد', 'خالد', 'فيصل', 'متساوون', 1, 'نحوِّل الجميع إلى أعداد عشرية لتسهيل المقارنة: 17/20 = 0.85، 4/5 = 0.8. لدينا: 0.85 (أحمد) > 0.84 (خالد) > 0.8 (فيصل). إذن الأعلى درجة هو أحمد.'),
  ('second', 0, 1, 'أيُّ الكسور التالية مرتَّبة تنازلياً ترتيباً صحيحاً؟', SHA2('أيُّ الكسور التالية مرتَّبة تنازلياً ترتيباً صحيحاً؟', 256),
   '5/6 > 3/4 > 7/12 > 1/2', '3/4 > 5/6 > 1/2 > 7/12', '1/2 > 7/12 > 3/4 > 5/6', '5/6 > 1/2 > 3/4 > 7/12', 1, 'نوحّد بمقام مشترك = 12: 5/6 = 10/12، 3/4 = 9/12، 7/12 = 7/12، 1/2 = 6/12. الترتيب التنازلي: 10/12 > 9/12 > 7/12 > 6/12 أي 5/6 > 3/4 > 7/12 > 1/2.'),
  ('second', 0, 1, 'اقترحت طالبة طريقة سريعة لمقارنة الكسرين 7/12 و9/16: «الكسر ذو البسط الأكبر هو الأكبر». هل هذا صحيح، ولماذا؟', SHA2('اقترحت طالبة طريقة سريعة لمقارنة الكسرين 7/12 و9/16: «الكسر ذو البسط الأكبر هو الأكبر». هل هذا صحيح، ولماذا؟', 256),
   'صحيح دائماً لأن البسط يدلّ على العدد', 'خطأ؛ يجب توحيد المقامات أولاً ثم المقارنة', 'صحيح فقط في الكسور الموجبة', 'صحيح في الأعداد العشرية فقط', 2, 'هذه قاعدة خاطئة. بتوحيد المقامين بمقام مشترك 48: 7/12 = 28/48، 9/16 = 27/48. إذن 7/12 > 9/16، رغم أن البسط 7 أصغر من 9. القاعدة الصحيحة: مقارنة البسط تكون بعد توحيد المقامات. هذا خطأ منطقي شائع لدى الطلاب.'),
  ('second', 0, 1, 'إذا كان أ كسراً موجباً أصغر من 1، أيُّ من العبارات التالية صحيح؟', SHA2('إذا كان أ كسراً موجباً أصغر من 1، أيُّ من العبارات التالية صحيح؟', 256),
   '1/أ < أ', '1/أ > 1', '1/أ = أ', '1/أ < 0', 2, 'إذا كان 0 < أ < 1 (مثل 1/2)، فإن مقلوبه 1/أ يكون أكبر من 1 (مثل 2). جرّب: أ = 1/3 → 1/أ = 3 > 1. هذه خاصية مهمّة للأعداد النسبية الموجبة الأصغر من 1: مقلوبها أكبر منها وأكبر من 1.'),
  ('second', 0, 2, 'احسب: (2/3) × (5/7).', SHA2('احسب: (2/3) × (5/7).', 256),
   '10/21', '7/10', '10/10', '7/21', 1, 'نضرب البسط في البسط والمقام في المقام: 2 × 5 = 10، 3 × 7 = 21. الناتج 10/21، وهو في أبسط صورة لأن 10 و21 ليس بينهما عامل مشترك أكبر من 1.'),
  ('second', 0, 2, 'ما ناتج (-3/4) × (8/9)؟', SHA2('ما ناتج (-3/4) × (8/9)؟', 256),
   '-2/3', '-24/36', '-11/13', '2/3', 1, 'إشارة الضرب: سالب × موجب = سالب. نختصر قبل الضرب: 3 و9 يقبلان القسمة على 3 (3→1، 9→3)، و4 و8 يقبلان القسمة على 4 (4→1، 8→2). يتبقّى (-1/1) × (2/3) = -2/3.'),
  ('second', 0, 2, 'احسب 3/5 من 25.', SHA2('احسب 3/5 من 25.', 256),
   '15', '10', '5', '8', 1, 'كلمة «من» في الكسور تعني الضرب: (3/5) × 25 = (3 × 25)/5 = 75/5 = 15. تذكَّر: لإيجاد كسر من عدد، تضرب الكسر في العدد ثم تُبسِّط.'),
  ('second', 0, 2, 'ما ناتج (1/2) × (1/2) × (1/2)؟', SHA2('ما ناتج (1/2) × (1/2) × (1/2)؟', 256),
   '1/8', '3/8', '1/2', '1/6', 1, 'نضرب الكسور بالترتيب: (1×1×1)/(2×2×2) = 1/8. هذا هو الأساس لمفهوم الأسس الذي ستدرسه في درس القوى والأسس: (1/2)^3 = 1/8.'),
  ('second', 0, 2, 'احسب: 2 و1/3 × 3/4.', SHA2('احسب: 2 و1/3 × 3/4.', 256),
   '7/4', '1 و3/4', '(أ) و(ب) معاً', '5/7', 3, 'أولاً نحوِّل العدد الكسري إلى كسر غير فعلي: 2 و1/3 = (2×3 + 1)/3 = 7/3. ثم نضرب: (7/3) × (3/4) = 21/12 = 7/4. ويُكتب أيضاً 1 و3/4. كلتا الصورتين صحيحة.'),
  ('second', 0, 2, 'احسب ناتج: (-2/5) × (-3/8).', SHA2('احسب ناتج: (-2/5) × (-3/8).', 256),
   '3/20', '-3/20', '5/40', '-6/13', 1, 'إشارة سالب × سالب = موجب. نضرب: (2 × 3)/(5 × 8) = 6/40. نُبسِّط بقسمة البسط والمقام على 2: 3/20.'),
  ('second', 0, 2, 'في صحن طعام يسعُ 3/4 لتر، أحضر سعد 5 صحون. كم لتراً تحوي مجتمعةً؟', SHA2('في صحن طعام يسعُ 3/4 لتر، أحضر سعد 5 صحون. كم لتراً تحوي مجتمعةً؟', 256),
   '15/4 لتر = 3 و3/4 لتر', '5 و3/4 لتر', '20/4 لتر = 5 لتر', '3/20 لتر', 1, 'نضرب: 5 × (3/4) = 15/4 لتر. نحوّل إلى كسري: 15 ÷ 4 = 3 والباقي 3، أي 3 و3/4 لتر.'),
  ('second', 0, 2, 'احسب: (4/9) × (3/8) × (6/5).', SHA2('احسب: (4/9) × (3/8) × (6/5).', 256),
   '1/5', '72/360', '(أ) و(ب) معاً', '1/15', 3, 'نضرب البسط × البسط = 4×3×6 = 72، والمقام × المقام = 9×8×5 = 360. الناتج 72/360. ولتبسيطه نقسم على 72: 72÷72 = 1، 360÷72 = 5. الناتج 1/5. الخياران (أ) و(ب) متكافئان.'),
  ('second', 0, 2, 'إذا كانت مساحة مستطيل (5/6) م^2، وعرضه (2/3) م، فما طوله؟', SHA2('إذا كانت مساحة مستطيل (5/6) م^2، وعرضه (2/3) م، فما طوله؟', 256),
   '5/4 م', '10/18 م', '5/9 م', '1 و1/4 م', 1, 'المساحة = الطول × العرض، إذن الطول = المساحة ÷ العرض. القسمة على كسر = الضرب في مقلوبه: (5/6) ÷ (2/3) = (5/6) × (3/2) = 15/12 = 5/4. ويُكتب 1 و1/4 (الخيار د هو نفسه؛ لكن الإجابة الأدق رياضياً هي 5/4 كما في أ). كلاهما يعبّر عن نفس القيمة.'),
  ('second', 0, 2, 'إذا كان (أ × ب) = 3/8، وكان أ = -1/4، فما قيمة ب؟', SHA2('إذا كان (أ × ب) = 3/8، وكان أ = -1/4، فما قيمة ب؟', 256),
   '-3/2', '3/2', '-3/32', '-2/3', 1, 'ب = (3/8) ÷ (-1/4) = (3/8) × (-4/1) = -12/8 = -3/2. تحقَّق: (-1/4) × (-3/2) = 3/8 ✓. الإشارة: عند ضرب موجب في سالب لنحصل على موجب، يجب أن يكون المضروب الآخر سالباً.'),
  ('second', 0, 3, 'ما مقلوب (معكوس الضرب) للعدد -3/7؟', SHA2('ما مقلوب (معكوس الضرب) للعدد -3/7؟', 256),
   '-7/3', '3/7', '7/3', '-3/7', 1, 'مقلوب الكسر هو الكسر الذي إذا ضُرب فيه أعطى 1. لقلب أ/ب: نبدّل البسط بالمقام، مع الإبقاء على الإشارة. مقلوب -3/7 هو -7/3. تحقَّق: (-3/7) × (-7/3) = 21/21 = 1.'),
  ('second', 0, 3, 'احسب: (5/6) ÷ (2/3).', SHA2('احسب: (5/6) ÷ (2/3).', 256),
   '5/4', '10/18', '5/9', '1/2', 1, 'القسمة على كسر = الضرب في مقلوبه. (5/6) ÷ (2/3) = (5/6) × (3/2). نختصر 6 و3 على 3: (5/2) × (1/2) = 5/4. ويمكن أيضاً كتابتها 1 و1/4.'),
  ('second', 0, 3, 'احسب: 8 ÷ (4/5).', SHA2('احسب: 8 ÷ (4/5).', 256),
   '10', '32/5', '2/5', '32', 1, 'نُحوِّل 8 إلى كسر = 8/1، ثم نضرب في مقلوب 4/5: (8/1) × (5/4) = 40/4 = 10. تفسير عملي: لمعرفة كم 4/5 موجوداً في 8 → 10 مرات.'),
  ('second', 0, 3, 'ما ناتج (-6/7) ÷ (3/14)؟', SHA2('ما ناتج (-6/7) ÷ (3/14)؟', 256),
   '-4', '4', '-9/14', '-18/98', 1, '(-6/7) × (14/3) = -84/21 = -4. ويمكن الاختصار قبل الضرب: 6 و3 على 3 (6→2، 3→1)، و7 و14 على 7 (7→1، 14→2): (-2/1) × (2/1) = -4.'),
  ('second', 0, 3, 'احسب: (2 و1/2) ÷ (5/8).', SHA2('احسب: (2 و1/2) ÷ (5/8).', 256),
   '4', '25/16', '1 و9/16', '10/13', 1, 'نحوّل العدد الكسري: 2 و1/2 = 5/2. ثم: (5/2) ÷ (5/8) = (5/2) × (8/5) = 40/10 = 4.'),
  ('second', 0, 3, 'قطعة قماش طولها 9/2 متر، يُراد تقطيعها إلى قطع متساوية طول كل منها 3/4 متر. كم قطعة نحصل عليها؟', SHA2('قطعة قماش طولها 9/2 متر، يُراد تقطيعها إلى قطع متساوية طول كل منها 3/4 متر. كم قطعة نحصل عليها؟', 256),
   '6 قطع', '5 قطع', '12 قطعة', '3 قطع', 1, 'عدد القطع = الطول الكلي ÷ طول القطعة = (9/2) ÷ (3/4) = (9/2) × (4/3) = 36/6 = 6 قطع. درّب نفسك على ربط القسمة بمعنى «كم مرة تتكرّر».'),
  ('second', 0, 3, 'أيُّ المعادلات التالية صحيحة؟', SHA2('أيُّ المعادلات التالية صحيحة؟', 256),
   '(1/3) ÷ 4 = 1/12', '(1/3) ÷ 4 = 4/3', '(1/3) ÷ 4 = 12', '(1/3) ÷ 4 = 1/3', 1, 'القسمة على عدد صحيح = الضرب في مقلوبه (1/العدد): (1/3) ÷ 4 = (1/3) × (1/4) = 1/12. خطأ شائع: قلب الكسر بدلاً من قلب القاسم.'),
  ('second', 0, 3, 'احسب: (-2 و1/4) ÷ (-3/4).', SHA2('احسب: (-2 و1/4) ÷ (-3/4).', 256),
   '3', '-3', '1', '27/16', 1, 'نحوّل: -2 و1/4 = -9/4. ثم: (-9/4) ÷ (-3/4) = (-9/4) × (-4/3) = 36/12 = 3. الإشارة: سالب ÷ سالب = موجب.'),
  ('second', 0, 3, 'إذا كان حاصل قسمة عددين نسبيين موجبٍ وكسرٍ غيرِ فعلي يساوي 1 و1/2، فما هو حاصل قسمة العددين بترتيب معكوس؟', SHA2('إذا كان حاصل قسمة عددين نسبيين موجبٍ وكسرٍ غيرِ فعلي يساوي 1 و1/2، فما هو حاصل قسمة العددين بترتيب معكوس؟', 256),
   '2/3', '3/2', '1 و1/2', '-2/3', 1, 'إذا كان أ ÷ ب = 3/2، فإن ب ÷ أ = مقلوب الناتج = 2/3. ذلك لأن (أ/ب) و(ب/أ) عددان مقلوبان لبعضهما، وحاصل ضربهما 1.'),
  ('second', 0, 3, 'في كيس حلوى زنته 4 كجم، إذا كانت كل علبة تستهلك 2/5 كجم من الكيس، فبعد ملء كم علبة يتبقّى 2/5 كجم في الكيس؟', SHA2('في كيس حلوى زنته 4 كجم، إذا كانت كل علبة تستهلك 2/5 كجم من الكيس، فبعد ملء كم علبة يتبقّى 2/5 كجم في الكيس؟', 256),
   '9 علب', '10 علب', '8 علب', '11 علبة', 1, 'الحلوى المستهلَكة = 4 - 2/5 = 18/5 كجم. عدد العلب = (18/5) ÷ (2/5) = (18/5) × (5/2) = 90/10 = 9. لمراجعة: 9 علب × 2/5 = 18/5 كجم، يتبقّى 4 - 18/5 = 2/5 كجم ✓.'),
  ('second', 0, 4, 'احسب: 3/8 + 4/8.', SHA2('احسب: 3/8 + 4/8.', 256),
   '7/8', '7/16', '12/8', '1/8', 1, 'عند الجمع بمقامات متشابهة: نجمع البسطين ونُبقي المقام كما هو. 3 + 4 = 7، والمقام 8، فالناتج 7/8. خطأ شائع: جمع المقامين أيضاً.'),
  ('second', 0, 4, 'احسب: 9/11 - 4/11.', SHA2('احسب: 9/11 - 4/11.', 256),
   '5/11', '5/0', '13/11', '5/22', 1, 'عند الطرح بمقام متشابه: نطرح البسطين ونحتفظ بالمقام. 9 - 4 = 5، فيكون الناتج 5/11. لاحظ أن المقام لا يتغيّر.'),
  ('second', 0, 4, 'احسب: -2/9 + 5/9.', SHA2('احسب: -2/9 + 5/9.', 256),
   '3/9 = 1/3', '-7/9', '7/9', '-3/9', 1, 'نجمع البسطين مع مراعاة الإشارات: -2 + 5 = 3. والمقام 9. الناتج 3/9 = 1/3 بعد التبسيط.'),
  ('second', 0, 4, 'احسب: 7/12 - 11/12.', SHA2('احسب: 7/12 - 11/12.', 256),
   '-4/12 = -1/3', '4/12', '-1/12', '-18/12', 1, '7 - 11 = -4. الناتج -4/12، وعند تبسيطه (قسمة الطرفين على 4) = -1/3.'),
  ('second', 0, 4, 'احسب: 2 و3/7 + 1 و2/7.', SHA2('احسب: 2 و3/7 + 1 و2/7.', 256),
   '3 و5/7', '3 و1/7', '4 و5/14', '3 و5/14', 1, 'نجمع الأعداد الكسرية بجمع الجزء الصحيح مع الصحيح، والكسر مع الكسر: (2 + 1) + (3/7 + 2/7) = 3 + 5/7 = 3 و5/7.'),
  ('second', 0, 4, 'احسب: 5 و1/6 - 2 و5/6.', SHA2('احسب: 5 و1/6 - 2 و5/6.', 256),
   '2 و2/6 = 2 و1/3', '3 و4/6', '2 و-4/6', '3 و1/3', 1, 'بما أن 1/6 < 5/6، نستلف 1 من الـ5 الصحيحة: 5 و1/6 = 4 و7/6. ثم نطرح: (4 - 2) + (7/6 - 5/6) = 2 + 2/6 = 2 و1/3.'),
  ('second', 0, 4, 'وعاء يحوي 4 و3/8 لتراً من الماء، أُضيف إليه 2 و7/8 لتر. ما الكمية الإجمالية؟', SHA2('وعاء يحوي 4 و3/8 لتراً من الماء، أُضيف إليه 2 و7/8 لتر. ما الكمية الإجمالية؟', 256),
   '7 و2/8 = 7 و1/4 لتر', '6 و10/8 لتر', '6 و2/16 لتر', '7 و10/16 لتر', 1, 'نجمع الأجزاء الصحيحة 4 + 2 = 6، ونجمع الكسرين 3/8 + 7/8 = 10/8. نحوّل 10/8 إلى 1 و2/8. نضيفها إلى 6: 6 + 1 و2/8 = 7 و2/8 = 7 و1/4 لتر.'),
  ('second', 0, 4, 'بسِّط: 4/5 - 3/5 + 2/5.', SHA2('بسِّط: 4/5 - 3/5 + 2/5.', 256),
   '3/5', '1/5', '9/5', '-1/5', 1, 'نُجري العمليات بالترتيب من اليسار إلى اليمين: (4 - 3 + 2)/5 = 3/5. أو يمكن جمع الموجبات أولاً: (4+2) - 3 = 6 - 3 = 3، الناتج 3/5.'),
  ('second', 0, 4, 'أجرى محمد ثلاث رحلات في يوم: قطع 3/10 من المسافة الكلية صباحاً، و2/10 ظهراً، ثم رجع 1/10 من المسافة. كم يساوي صافي ما تقدّم به نحو الهدف؟', SHA2('أجرى محمد ثلاث رحلات في يوم: قطع 3/10 من المسافة الكلية صباحاً، و2/10 ظهراً، ثم رجع 1/10 من المسافة. كم يساوي صافي ما تقدّم به نحو الهدف؟', 256),
   '4/10 = 2/5 من المسافة', '5/10 من المسافة', '6/10 من المسافة', '1/10 من المسافة', 1, 'نجمع التقدّم ثم نطرح الرجوع: (3/10 + 2/10) - 1/10 = 5/10 - 1/10 = 4/10 = 2/5. لاحظ أن العمليات على مقام مشترك (10) فلا حاجة لتوحيد المقامات.'),
  ('second', 0, 4, 'إذا كان (س/9) + (4/9) = 1، فما قيمة س؟', SHA2('إذا كان (س/9) + (4/9) = 1، فما قيمة س؟', 256),
   '5', '13', '-5', '9', 1, 'نُبقي س/9 منفرداً: س/9 = 1 - 4/9 = 9/9 - 4/9 = 5/9. بمقارنة الكسرين بمقام مشترك يتبيّن أن س = 5. تحقَّق: (5/9) + (4/9) = 9/9 = 1 ✓.'),
  ('second', 0, 5, 'احسب: 1/2 + 1/3.', SHA2('احسب: 1/2 + 1/3.', 256),
   '5/6', '2/5', '1/6', '3/6', 1, 'المقام المشترك الأصغر للعددين 2 و3 هو 6. نحوّل: 1/2 = 3/6، 1/3 = 2/6. ثم نجمع البسطين: 3 + 2 = 5، فالناتج 5/6.'),
  ('second', 0, 5, 'احسب: 5/6 - 1/4.', SHA2('احسب: 5/6 - 1/4.', 256),
   '7/12', '4/2', '4/12', '5/24', 1, 'م.م.أ للمقامين 6 و4 هو 12. نحوّل: 5/6 = 10/12، 1/4 = 3/12. نطرح: 10 - 3 = 7. الناتج 7/12.'),
  ('second', 0, 5, 'احسب: 2/5 + 3/10.', SHA2('احسب: 2/5 + 3/10.', 256),
   '7/10', '5/15', '5/10', '1/2', 1, 'م.م.أ للمقامين 5 و10 هو 10. نحوّل: 2/5 = 4/10، و3/10 تبقى كما هي. نجمع: 4 + 3 = 7. الناتج 7/10. (لاحظ: 7/10 لا يساوي 1/2 = 5/10.)'),
  ('second', 0, 5, 'احسب: 3/8 - 1/6.', SHA2('احسب: 3/8 - 1/6.', 256),
   '5/24', '2/2', '2/24', '1/12', 1, 'م.م.أ للمقامين 8 و6: نحلّل 8 = 2^3 و6 = 2×3، فالم.م.أ = 2^3×3 = 24. نحوّل: 3/8 = 9/24، 1/6 = 4/24. نطرح: 9 - 4 = 5. الناتج 5/24.'),
  ('second', 0, 5, 'احسب: 2 و1/3 + 1 و1/4.', SHA2('احسب: 2 و1/3 + 1 و1/4.', 256),
   '3 و7/12', '3 و2/7', '4 و1/12', '3 و1/12', 1, 'نجمع الجزء الصحيح: 2 + 1 = 3. ثم الكسرين: 1/3 + 1/4. م.م.أ = 12: 1/3 = 4/12، 1/4 = 3/12، المجموع 7/12. الناتج النهائي 3 و7/12.'),
  ('second', 0, 5, 'احسب: 4 و1/6 - 1 و3/4.', SHA2('احسب: 4 و1/6 - 1 و3/4.', 256),
   '2 و5/12', '3 و-7/12', '2 و1/2', '2 و7/12', 1, 'م.م.أ = 12. نحوّل: 4 و1/6 = 4 و2/12، و1 و3/4 = 1 و9/12. بما أن 2/12 < 9/12، نستلف 1: 4 و2/12 = 3 و14/12. نطرح: (3 - 1) + (14/12 - 9/12) = 2 و5/12.'),
  ('second', 0, 5, 'اشترى ماجد قطعة قماش طولها 2 و1/2 متر، استخدم منها 3/4 متر. كم يتبقّى؟', SHA2('اشترى ماجد قطعة قماش طولها 2 و1/2 متر، استخدم منها 3/4 متر. كم يتبقّى؟', 256),
   '1 و3/4 متر', '1 و1/4 متر', '2 و-1/4 متر', '1 و1/2 متر', 1, 'نحوّل: 2 و1/2 = 5/2 = 10/4. ثم: 10/4 - 3/4 = 7/4. نحوّل إلى عدد كسري: 7 ÷ 4 = 1 وباقي 3، أي 1 و3/4 متر.'),
  ('second', 0, 5, 'احسب: -1/3 + 2/5.', SHA2('احسب: -1/3 + 2/5.', 256),
   '1/15', '-1/15', '1/2', '-7/15', 1, 'م.م.أ = 15. نحوّل: -1/3 = -5/15، 2/5 = 6/15. نجمع: -5 + 6 = 1. الناتج 1/15. (طرح القيم المطلقة، والإشارة للأكبر منهما: 6/15 موجب وهو الأكبر، فالنتيجة موجبة.)'),
  ('second', 0, 5, 'في يوم دراسي مدّته 6 ساعات، استغرق أحمد 1/2 ساعة في الفطور و1 و1/4 ساعة في حصة الرياضيات و3/4 ساعة في الرياضة. كم تبقّى من اليوم الدراسي؟', SHA2('في يوم دراسي مدّته 6 ساعات، استغرق أحمد 1/2 ساعة في الفطور و1 و1/4 ساعة في حصة الرياضيات و3/4 ساعة في الرياضة. كم تبقّى من اليوم الدراسي؟', 256),
   '3 و1/2 ساعة', '3 و3/4 ساعة', '4 ساعات', '2 و3/4 ساعة', 1, 'المستهلَك = 1/2 + 1 و1/4 + 3/4. م.م.أ = 4: (2/4) + (1 و1/4) + (3/4) = 1 و(2/4 + 1/4 + 3/4) = 1 و6/4 = 1 + 1 و2/4 = 2 و1/2. المتبقّي = 6 - 2 و1/2 = 3 و1/2 ساعة.'),
  ('second', 0, 5, 'أيُّ القيم تجعل المعادلة صحيحة:  2/3 + س = 5/6.', SHA2('أيُّ القيم تجعل المعادلة صحيحة:  2/3 + س = 5/6.', 256),
   '1/6', '3/3', '1/3', '-1/6', 1, 'نعزل س: س = 5/6 - 2/3. نوحّد: 2/3 = 4/6. س = 5/6 - 4/6 = 1/6. تحقَّق: 2/3 + 1/6 = 4/6 + 1/6 = 5/6 ✓.'),
  ('second', 0, 6, 'ما قيمة 2^5؟', SHA2('ما قيمة 2^5؟', 256),
   '32', '10', '16', '25', 1, 'العدد ذو الأس يدلّ على عدد مرّات ضرب الأساس بنفسه: 2^5 = 2×2×2×2×2 = 32. خطأ شائع: ضرب الأساس في الأس (2 × 5 = 10).'),
  ('second', 0, 6, 'اكتب 7 × 7 × 7 × 7 على صورة قوّة.', SHA2('اكتب 7 × 7 × 7 × 7 على صورة قوّة.', 256),
   '7^4', '4^7', '7×4', '28', 1, 'الأساس هو العدد المتكرّر = 7. الأس هو عدد مرّات التكرار = 4. إذن الكتابة = 7^4. الصورة الموسّعة 7×7×7×7 = 2401.'),
  ('second', 0, 6, 'ما قيمة 3^3؟', SHA2('ما قيمة 3^3؟', 256),
   '27', '9', '6', '12', 1, '3^3 = 3 × 3 × 3 = 9 × 3 = 27. لاحظ الفرق بين 3^3 (= 27) و3 × 3 (= 9) و3 + 3 + 3 (= 9).'),
  ('second', 0, 6, 'ما قيمة 10^4؟', SHA2('ما قيمة 10^4؟', 256),
   '10000', '40', '1000', '10^4 = 10^4', 1, 'قاعدة قوى العشرة: 10ⁿ = 1 يليه ن من الأصفار. 10^4 = 10000 (أربعة أصفار). تذكَّر: 10^2 = 100، 10^3 = 1000، 10^4 = 10000.'),
  ('second', 0, 6, 'أوجد قيمة العبارة: 2^3 + 3^2.', SHA2('أوجد قيمة العبارة: 2^3 + 3^2.', 256),
   '17', '13', '10', '25', 1, 'نحسب كل قوّة على حدة ثم نجمع: 2^3 = 8، 3^2 = 9، إذن 8 + 9 = 17. تطبيق ترتيب العمليات: نُجري الأسس قبل الجمع.'),
  ('second', 0, 6, 'ما قيمة (-2)^4؟', SHA2('ما قيمة (-2)^4؟', 256),
   '16', '-16', '-8', '8', 1, 'بما أن الأس زوجي (4)، فالناتج موجب: (-2)^4 = (-2)×(-2)×(-2)×(-2) = 4 × 4 = 16. لو كان الأس فردياً لكان الناتج سالباً. ميِّز بين (-2)^4 = 16 و -2^4 = -16.'),
  ('second', 0, 6, 'ما قيمة (1/2)^3؟', SHA2('ما قيمة (1/2)^3؟', 256),
   '1/8', '3/2', '1/6', '1/4', 1, '(1/2)^3 = (1/2)×(1/2)×(1/2) = 1^3/2^3 = 1/8. عند رفع الكسر إلى أس، نرفع البسط والمقام إلى ذلك الأس.'),
  ('second', 0, 6, 'أوجد قيمة: 5^2 × 5^3.', SHA2('أوجد قيمة: 5^2 × 5^3.', 256),
   '5^5 = 3125', '5^6 = 15625', '25^5', '10^5', 1, 'خاصية ضرب القوى ذات الأساس نفسه: نُبقي الأساس ونجمع الأسس. 5^2 × 5^3 = 5^2+3 = 5^5 = 3125.'),
  ('second', 0, 6, 'أوجد قيمة: 2^3 × 2^2 ÷ 2^4.', SHA2('أوجد قيمة: 2^3 × 2^2 ÷ 2^4.', 256),
   '2', '4', '1', '8', 1, 'بخصائص القوى: 2^3 × 2^2 = 2^5، ثم 2^5 ÷ 2^4 = 2^5-4 = 2^1 = 2. أو حسابياً: 8 × 4 = 32، و32 ÷ 16 = 2.'),
  ('second', 0, 6, 'إذا كان حجم مكعّب طول حرفه (2/3) وحدة، فما حجمه؟', SHA2('إذا كان حجم مكعّب طول حرفه (2/3) وحدة، فما حجمه؟', 256),
   '8/27 وحدة مكعّبة', '2/3 وحدة مكعّبة', '6/9 وحدة مكعّبة', '8/9 وحدة مكعّبة', 1, 'حجم المكعّب = (طول الحرف)^3 = (2/3)^3 = 2^3/3^3 = 8/27. تطبيق مهم لرفع الكسر إلى قوّة. خطأ شائع: رفع البسط فقط أو ضرب الكسر في 3.'),
  ('second', 0, 7, 'أيٌّ من التالي مكتوب بالصيغة العلمية الصحيحة؟', SHA2('أيٌّ من التالي مكتوب بالصيغة العلمية الصحيحة؟', 256),
   '3.5 × 10^4', '35 × 10^3', '0.35 × 10^5', '3.5 × 4^10', 1, 'الصيغة العلمية تشترط: (1) المعامل عدد عشري ≥ 1 وأصغر من 10، (2) القوّة من 10. الخيار (أ) يحقّق الشرطين. الخيار (ب) معامله 35 (أكبر من 10)، (ج) معامله 0.35 (أصغر من 1)، (د) قوّته من 4 لا من 10.'),
  ('second', 0, 7, 'اكتب 540000 بالصيغة العلمية.', SHA2('اكتب 540000 بالصيغة العلمية.', 256),
   '5.4 × 10^5', '54 × 10^4', '5.4 × 10^4', '0.54 × 10^6', 1, 'نحرّك الفاصلة من اليمين إلى اليسار حتى نصل إلى عدد بين 1 و10. 540000 → 5.40000؛ تحرّكت الفاصلة 5 خانات. إذن الصيغة 5.4 × 10^5.'),
  ('second', 0, 7, 'اكتب 0.0007 بالصيغة العلمية.', SHA2('اكتب 0.0007 بالصيغة العلمية.', 256),
   '7 × 10^-4', '7 × 10^4', '0.7 × 10^-3', '7 × 10^-3', 1, 'نحرّك الفاصلة إلى اليمين 4 خانات لنصل إلى 7. لأن العدد الأصلي أصغر من 1، يكون الأس سالباً. الصيغة: 7 × 10^-4.'),
  ('second', 0, 7, 'اكتب 6.2 × 10^3 بالصيغة القياسية.', SHA2('اكتب 6.2 × 10^3 بالصيغة القياسية.', 256),
   '6200', '620', '62000', '0.0062', 1, 'الأس 3 موجب، فنحرّك الفاصلة 3 خانات إلى اليمين: 6.2 → 6200. (أضف أصفاراً عند اللزوم).'),
  ('second', 0, 7, 'اكتب 0.000045 بالصيغة العلمية.', SHA2('اكتب 0.000045 بالصيغة العلمية.', 256),
